// src/components/Footers/footer.recharche.js - شريط بحث ثابت في أسفل الشاشة
import React, { useState } from "react";

export default function FooterRecharche({ type, onSearch, placeholder }) {
  const [searchTerm, setSearchTerm] = useState("");

  const handleSearch = (value) => {
    setSearchTerm(value);
    if (onSearch) {
      onSearch(value);
    }
  };

  const getPlaceholder = () => {
    if (placeholder) return placeholder;
    if (type === "restaurants") {
      return "🔍 Rechercher un restaurant par nom, ville ou description...";
    }
    if (type === "employees") {
      return "🔍 Rechercher un employé par nom, métier, ville ou restaurant...";
    }
    return "🔍 Rechercher...";
  };

  const styles = `
    .search-footer {
      position: fixed;
      bottom: 0;
      left: 0;
      right: 0;
      z-index: 1000;
      background: linear-gradient(135deg, #9b2dff, #7c3aed, #a855f7);
      padding: 15px 20px;
      box-shadow: 0 -5px 20px rgba(0, 0, 0, 0.3);
      border-top: 1px solid rgba(255, 255, 255, 0.2);
    }
    
    .search-container {
      max-width: 600px;
      margin: 0 auto;
      position: relative;
    }
    
    .search-icon {
      position: absolute;
      left: 15px;
      top: 50%;
      transform: translateY(-50%);
      color: rgba(255, 255, 255, 0.7);
      font-size: 1rem;
      z-index: 1;
    }
    
    .search-input {
      width: 100%;
      padding: 12px 20px 12px 45px;
      background: rgba(255, 255, 255, 0.15);
      border: 1px solid rgba(255, 255, 255, 0.3);
      border-radius: 50px;
      color: white;
      font-size: 0.9rem;
      transition: all 0.3s ease;
    }
    
    .search-input:focus {
      outline: none;
      border-color: #e9d5ff;
      background: rgba(255, 255, 255, 0.25);
      box-shadow: 0 0 15px rgba(255, 255, 255, 0.2);
    }
    
    .search-input::placeholder {
      color: rgba(255, 255, 255, 0.6);
      font-size: 0.85rem;
    }
    
    .clear-btn {
      position: absolute;
      right: 15px;
      top: 50%;
      transform: translateY(-50%);
      background: none;
      border: none;
      color: rgba(255, 255, 255, 0.7);
      cursor: pointer;
      font-size: 1rem;
      padding: 5px;
      transition: all 0.2s;
      border-radius: 50%;
    }
    
    .clear-btn:hover {
      color: white;
      background: rgba(255, 255, 255, 0.2);
    }
    
    .search-stats {
      text-align: center;
      margin-top: 8px;
      font-size: 0.7rem;
      color: rgba(255, 255, 255, 0.5);
    }
    
    @media (max-width: 768px) {
      .search-footer {
        padding: 10px 15px;
      }
      
      .search-input {
        padding: 10px 15px 10px 40px;
        font-size: 0.85rem;
      }
      
      .search-icon {
        left: 12px;
        font-size: 0.85rem;
      }
    }
  `;

  return (
    <>
      <style>{styles}</style>
      <div className="search-footer">
        <div className="search-container">
          <div className="search-icon">
            <i className="fas fa-search"></i>
          </div>
          <input
            type="text"
            className="search-input"
            placeholder={getPlaceholder()}
            value={searchTerm}
            onChange={(e) => handleSearch(e.target.value)}
          />
          {searchTerm && (
            <button className="clear-btn" onClick={() => handleSearch("")}>
              <i className="fas fa-times"></i>
            </button>
          )}
        </div>
        {searchTerm && (
          <div className="search-stats">
            <i className="fas fa-filter"></i> Filtre actif: "{searchTerm}"
          </div>
        )}
      </div>
    </>
  );
}
